"""API Server with mixed deprecated and active endpoints."""
import json
import csv
import io
from datetime import datetime
from typing import Dict, Any, List, Optional


def format_response(data: Any, status: int = 200, message: str = "ok") -> Dict:
    """Format a standard API response. Used by ALL endpoints."""
    return {
        'status': status,
        'message': message,
        'data': data,
        'timestamp': datetime.now().isoformat(),
    }


def validate_auth(headers: Dict) -> bool:
    """Validate authentication token. Used by ALL endpoints."""
    token = headers.get('Authorization', '')
    return token.startswith('Bearer ') and len(token) > 10


def _parse_legacy_user(raw: str) -> Dict:
    """Parse user from old pipe-delimited format. ONLY used by legacy-users endpoint."""
    parts = raw.split('|')
    if len(parts) < 3:
        return None
    return {
        'name': parts[0].strip(),
        'email': parts[1].strip(),
        'role': parts[2].strip(),
    }


def _generate_pdf(data: Dict) -> bytes:
    """Generate a PDF report. ONLY used by report-pdf endpoint."""
    # Simplified: just return a fake PDF header
    content = f"Report: {json.dumps(data)}"
    return b'%PDF-1.4\n' + content.encode()


def _process_csv_row(row: List[str], headers: List[str]) -> Dict:
    """Process a single CSV row into a dict. ONLY used by import-csv endpoint."""
    result = {}
    for i, header in enumerate(headers):
        if i < len(row):
            result[header.strip()] = row[i].strip()
    return result


# ============================================================
# ACTIVE ENDPOINTS (keep these)
# ============================================================

def handle_get_users(request: Dict) -> Dict:
    """GET /api/v2/users - List users in new format."""
    if not validate_auth(request.get('headers', {})):
        return format_response(None, 401, 'Unauthorized')

    page = request.get('params', {}).get('page', 1)
    limit = request.get('params', {}).get('limit', 10)

    # Simulated user data
    users = [
        {'id': i, 'name': f'User {i}', 'email': f'user{i}@example.com', 'active': True}
        for i in range(1, limit + 1)
    ]

    return format_response({
        'users': users,
        'page': page,
        'total': 100,
    })


def handle_create_user(request: Dict) -> Dict:
    """POST /api/v2/users - Create a new user."""
    if not validate_auth(request.get('headers', {})):
        return format_response(None, 401, 'Unauthorized')

    body = request.get('body', {})
    if not body.get('name') or not body.get('email'):
        return format_response(None, 400, 'Missing required fields: name, email')

    user = {
        'id': 42,
        'name': body['name'],
        'email': body['email'],
        'active': True,
        'created_at': datetime.now().isoformat(),
    }
    return format_response(user, 201, 'User created')


def handle_get_reports(request: Dict) -> Dict:
    """GET /api/v2/reports - List reports in JSON format."""
    if not validate_auth(request.get('headers', {})):
        return format_response(None, 401, 'Unauthorized')

    report_type = request.get('params', {}).get('type', 'summary')

    reports = [
        {'id': 1, 'type': report_type, 'title': 'Q1 Report', 'status': 'complete'},
        {'id': 2, 'type': report_type, 'title': 'Q2 Report', 'status': 'pending'},
    ]

    return format_response({'reports': reports, 'count': len(reports)})


def handle_import_json(request: Dict) -> Dict:
    """POST /api/v2/import - Import data from JSON."""
    if not validate_auth(request.get('headers', {})):
        return format_response(None, 401, 'Unauthorized')

    body = request.get('body', {})
    records = body.get('records', [])

    if not records:
        return format_response(None, 400, 'No records to import')

    imported = len(records)
    return format_response({'imported': imported, 'failed': 0}, 200, f'Imported {imported} records')


def handle_health(request: Dict) -> Dict:
    """GET /api/health - Health check endpoint."""
    return format_response({'healthy': True, 'version': '2.0.0'})


# ============================================================
# DEPRECATED ENDPOINTS (remove these)
# ============================================================

# @deprecated - replaced by handle_get_users
def handle_legacy_users(request: Dict) -> Dict:
    """GET /api/v1/legacy-users - List users in old pipe-delimited format."""
    if not validate_auth(request.get('headers', {})):
        return format_response(None, 401, 'Unauthorized')

    # Old format: name|email|role
    raw_users = [
        'Alice|alice@example.com|admin',
        'Bob|bob@example.com|user',
        'Charlie|charlie@example.com|user',
    ]

    users = [_parse_legacy_user(u) for u in raw_users]
    users = [u for u in users if u is not None]
    return format_response(users)


# @deprecated - replaced by handle_import_json
def handle_import_csv(request: Dict) -> Dict:
    """POST /api/v1/import-csv - Import data from CSV."""
    if not validate_auth(request.get('headers', {})):
        return format_response(None, 401, 'Unauthorized')

    body = request.get('body', {})
    csv_content = body.get('csv', '')

    if not csv_content:
        return format_response(None, 400, 'No CSV data provided')

    reader = csv.reader(io.StringIO(csv_content))
    headers = next(reader, None)
    if not headers:
        return format_response(None, 400, 'Empty CSV')

    records = [_process_csv_row(row, headers) for row in reader]
    return format_response({'imported': len(records)}, 200, f'Imported {len(records)} CSV records')


# @deprecated - replaced by handle_get_reports
def handle_report_pdf(request: Dict) -> Dict:
    """GET /api/v1/report-pdf - Generate a PDF report."""
    if not validate_auth(request.get('headers', {})):
        return format_response(None, 401, 'Unauthorized')

    report_data = {
        'title': request.get('params', {}).get('title', 'Report'),
        'date': datetime.now().isoformat(),
        'summary': 'Generated report data',
    }

    pdf_bytes = _generate_pdf(report_data)
    return format_response({'pdf_size': len(pdf_bytes), 'format': 'pdf'})


# Route table
ROUTES = {
    'GET /api/v2/users': handle_get_users,
    'POST /api/v2/users': handle_create_user,
    'GET /api/v2/reports': handle_get_reports,
    'POST /api/v2/import': handle_import_json,
    'GET /api/health': handle_health,
    # Deprecated routes
    'GET /api/v1/legacy-users': handle_legacy_users,
    'POST /api/v1/import-csv': handle_import_csv,
    'GET /api/v1/report-pdf': handle_report_pdf,
}


def dispatch(method: str, path: str, request: Dict) -> Dict:
    """Route a request to the appropriate handler."""
    route_key = f'{method} {path}'
    handler = ROUTES.get(route_key)
    if handler is None:
        return format_response(None, 404, f'Not found: {route_key}')
    return handler(request)

