import sys
import os
sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
from server import dispatch, format_response, validate_auth, ROUTES


AUTH_HEADERS = {'Authorization': 'Bearer valid_token_12345'}


def test_format_response():
    resp = format_response({'key': 'value'}, 200, 'ok')
    assert resp['status'] == 200
    assert resp['message'] == 'ok'
    assert resp['data'] == {'key': 'value'}
    assert 'timestamp' in resp


def test_validate_auth():
    assert validate_auth({'Authorization': 'Bearer valid_token'}) is True
    assert validate_auth({'Authorization': 'Bearer x'}) is False  # too short
    assert validate_auth({}) is False


def test_get_users():
    resp = dispatch('GET', '/api/v2/users', {'headers': AUTH_HEADERS})
    assert resp['status'] == 200
    assert 'users' in resp['data']
    assert len(resp['data']['users']) > 0


def test_get_users_unauth():
    resp = dispatch('GET', '/api/v2/users', {'headers': {}})
    assert resp['status'] == 401


def test_create_user():
    resp = dispatch('POST', '/api/v2/users', {
        'headers': AUTH_HEADERS,
        'body': {'name': 'Test', 'email': 'test@example.com'},
    })
    assert resp['status'] == 201
    assert resp['data']['name'] == 'Test'


def test_create_user_missing_fields():
    resp = dispatch('POST', '/api/v2/users', {
        'headers': AUTH_HEADERS,
        'body': {'name': 'Test'},
    })
    assert resp['status'] == 400


def test_get_reports():
    resp = dispatch('GET', '/api/v2/reports', {'headers': AUTH_HEADERS})
    assert resp['status'] == 200
    assert 'reports' in resp['data']
    assert resp['data']['count'] == 2


def test_import_json():
    resp = dispatch('POST', '/api/v2/import', {
        'headers': AUTH_HEADERS,
        'body': {'records': [{'a': 1}, {'b': 2}]},
    })
    assert resp['status'] == 200
    assert resp['data']['imported'] == 2


def test_import_json_empty():
    resp = dispatch('POST', '/api/v2/import', {
        'headers': AUTH_HEADERS,
        'body': {'records': []},
    })
    assert resp['status'] == 400


def test_health():
    resp = dispatch('GET', '/api/health', {})
    assert resp['status'] == 200
    assert resp['data']['healthy'] is True


def test_not_found():
    resp = dispatch('GET', '/api/nonexistent', {})
    assert resp['status'] == 404


def test_deprecated_routes_removed():
    """Verify deprecated routes are no longer in the route table."""
    assert 'GET /api/v1/legacy-users' not in ROUTES
    assert 'POST /api/v1/import-csv' not in ROUTES
    assert 'GET /api/v1/report-pdf' not in ROUTES


def test_active_routes_present():
    """Verify all active routes still exist."""
    assert 'GET /api/v2/users' in ROUTES
    assert 'POST /api/v2/users' in ROUTES
    assert 'GET /api/v2/reports' in ROUTES
    assert 'POST /api/v2/import' in ROUTES
    assert 'GET /api/health' in ROUTES


def test_format_response_is_importable():
    """format_response must still be importable (shared utility)."""
    from server import format_response
    resp = format_response('test')
    assert resp['data'] == 'test'


def test_validate_auth_is_importable():
    """validate_auth must still be importable (shared utility)."""
    from server import validate_auth
    assert validate_auth({'Authorization': 'Bearer test_token_xx'}) is True

